import React, { useState } from 'react';
import { register } from '../api';
import { Link } from 'react-router-dom';

export default function Register({ onLogin }) {
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);

  async function handleSubmit(e) {
    e.preventDefault();
    setLoading(true);
    setError('');
    const data = await register(username, password);
    setLoading(false);
    if (data.token) {
      onLogin(data.token);
    } else {
      setError(data.message || 'Registration failed');
    }
  }

  return (
    <div style={styles.container}>
      <div style={styles.card}>
        <h1 style={styles.logo}>💹 PEX</h1>
        <h2 style={styles.title}>Create Account</h2>
        <p style={styles.sub}>Start with $10,000 wallet. Issue your own stock.</p>
        {error && <div style={styles.error}>{error}</div>}
        <form onSubmit={handleSubmit}>
          <input
            style={styles.input}
            placeholder="Username"
            value={username}
            onChange={e => setUsername(e.target.value)}
            required
          />
          <input
            style={styles.input}
            type="password"
            placeholder="Password"
            value={password}
            onChange={e => setPassword(e.target.value)}
            required
          />
          <button style={styles.button} disabled={loading}>
            {loading ? 'Creating...' : 'Create Account'}
          </button>
        </form>
        <p style={styles.link}>
          Have account? <Link to="/login">Sign in</Link>
        </p>
      </div>
    </div>
  );
}

const styles = {
  container: { minHeight: '100vh', background: '#0a0a0f', display: 'flex', alignItems: 'center', justifyContent: 'center' },
  card: { background: '#13131a', border: '1px solid #2a2a3a', borderRadius: 16, padding: 40, width: 360 },
  logo: { textAlign: 'center', fontSize: 36, margin: '0 0 8px' },
  title: { textAlign: 'center', color: '#fff', margin: '0 0 6px', fontWeight: 600 },
  sub: { textAlign: 'center', color: '#666', fontSize: 13, marginBottom: 24 },
  error: { background: '#2d0f0f', color: '#ff6b6b', padding: '10px 14px', borderRadius: 8, marginBottom: 16, fontSize: 14 },
  input: {
    width: '100%', padding: '12px 14px', marginBottom: 14, borderRadius: 8,
    border: '1px solid #2a2a3a', background: '#1a1a24', color: '#fff',
    fontSize: 15, boxSizing: 'border-box', outline: 'none',
  },
  button: {
    width: '100%', padding: '13px', borderRadius: 8, border: 'none',
    background: 'linear-gradient(135deg, #00d4aa, #00a896)', color: '#000',
    fontWeight: 700, fontSize: 15, cursor: 'pointer',
  },
  link: { textAlign: 'center', color: '#666', marginTop: 20, fontSize: 14 },
};
